CREATE OR REPLACE VIEW `vplantstatus` AS select `p`.`plantId` AS `plantId`,`p`.`acquisitionDate` AS `acquisitionDate`,`p`.`acquisitionSource` AS `acquisitionSource`,`p`.`plantTag` AS `plantTag`,trim((case when (`t`.`isSystemManaged` = 1) then concat(`g`.`genusName`,' sp.') when (`t`.`speciesName` is not null) then concat(`g`.`genusName`,' ',`t`.`speciesName`) when (`t`.`hybridName` is not null) then concat(`g`.`genusName`,' ',`t`.`hybridName`) else `g`.`genusName` end)) AS `displayName`,`t`.`isActive` AS `taxonIsActive`,`g`.`isActive` AS `genusIsActive`,`l`.`locationName` AS `locationName`,`lf`.`startDate` AS `lastFlowerDate`,`lr`.`repotDate` AS `lastRepotDate`,`gm`.`name` AS `currentGrowthMediumName`,`lfeed`.`eventDateTime` AS `lastFeedDate`,`ot`.`displayName` AS `lastFeedTypeName` from (((((((((`plant` `p` left join `taxon` `t` on((`t`.`taxonId` = `p`.`taxonId`))) left join `genus` `g` on((`g`.`genusId` = `t`.`genusId`))) left join `plantlocationhistory` `clh` on((`clh`.`plantLocationHistoryId` = (select `plh`.`plantLocationHistoryId` from `plantlocationhistory` `plh` where ((`plh`.`plantId` = `p`.`plantId`) and (`plh`.`isActive` = 1)) order by `plh`.`startDateTime` desc limit 1)))) left join `location` `l` on((`l`.`locationId` = `clh`.`locationId`))) left join `flowering` `lf` on((`lf`.`floweringId` = (select `f`.`floweringId` from `flowering` `f` where ((`f`.`plantId` = `p`.`plantId`) and (`f`.`isActive` = 1)) order by `f`.`startDate` desc limit 1)))) left join `repotting` `lr` on((`lr`.`repottingId` = (select `r`.`repottingId` from `repotting` `r` where ((`r`.`plantId` = `p`.`plantId`) and (`r`.`isActive` = 1)) order by `r`.`repotDate` desc limit 1)))) left join `growthmedium` `gm` on((`gm`.`growthMediumId` = `lr`.`newGrowthMediumId`))) left join `plantevent` `lfeed` on((`lfeed`.`plantEventId` = (select `pe`.`plantEventId` from (`plantevent` `pe` join `observationtype` `o` on(((`o`.`Id` = `pe`.`observationTypeId`) and (`o`.`isActive` = 1) and (`o`.`typeCode` like 'OBS_FEED%')))) where ((`pe`.`plantId` = `p`.`plantId`) and (`pe`.`isActive` = 1)) order by `pe`.`eventDateTime` desc limit 1)))) left join `observationtype` `ot` on((`ot`.`Id` = `lfeed`.`observationTypeId`))) where ((`p`.`isActive` = 1) and (`p`.`endDate` is null));

